sql:
SELECT COUNT(*) AS in_progress_episodes
FROM rl_episodes
WHERE episode_status = 'in_progress';

SELECT agent_name AS "Agent Name"
FROM agents
ORDER BY agent_name;

SELECT episode_id, total_reward
FROM rl_episodes
WHERE episode_status = 'in_progress';

external_knowledge:
; In the context of reinforcement learning, an episode represents a sequence of actions taken by an agent within an environment to achieve a specific goal; 
; The status 'completed' indicates that the episode has ended, either because the agent achieved its goal or the maximum number of steps was reached; 
; The performance metrics provide insights into how well different environments support the training of agents.
